#include<bits/stdc++.h>
using namespace std;
int n,m,s[2000010],a[2000010],b[2000010];
long long ans;
void mergesort(int l,int r)
{
    if(l>=r)
    {
        return;
    }
    int mid=(l+r)/2;
    mergesort(l,mid);
    mergesort(mid+1,r);
    int i=l,j=mid+1,tot=l;
    while(i<=mid&&j<=r)
    {
        if(a[i]>=a[j])
        {
            b[tot++]=a[i++];
        }
        else
        {
            b[tot++]=a[j++];
            ans+=mid-i+1;
        }
    }
    while(i<=mid)
    {
        b[tot++]=a[i++];
    }
    while(j<=r)
    {
        b[tot++]=a[j++];
    }
    for(int k=l;k<=r;k++)
    {
        a[k]=b[k];
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&s[i]);
        s[i]-=m;
        a[i]=a[i-1]+s[i];
    }
    mergesort(0,n);
    printf("%lld",ans%92084931);
    return 0;
}
